import{_ as o,C as s,o as i,c,j as t,a,E as r,a3 as d}from"./chunks/framework.oxq6d-og.js";const y=JSON.parse('{"title":"NThread call lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"en/nthread/call-lifecycle.md","filePath":"en/nthread/call-lifecycle.md"}'),l={name:"en/nthread/call-lifecycle.md"};function h(p,e,u,m,g,f){const n=s("NThreadSimulator");return i(),c("div",null,[e[0]||(e[0]=t("h1",{id:"nthread-call-lifecycle",tabindex:"-1"},[a("NThread call lifecycle "),t("a",{class:"header-anchor",href:"#nthread-call-lifecycle","aria-label":'Permalink to "NThread call lifecycle"'},"​")],-1)),e[1]||(e[1]=t("p",null,[a("One "),t("code",null,"NThread"),a(" redirects exactly one OS thread for its lifetime. With the factory path, thread selection happens during initialization and "),t("code",null,"createAccessor()"),a(" resolves only after that work completes.")],-1)),e[2]||(e[2]=t("p",null,[a("In the slowed model below, each clock edge advances one instruction. Rather than displaying every code region at once, the disassembly window follows "),t("code",null,"RIP"),a(" between native code, separate stub locations in different modules, and a demo target. Its nine instruction groups and memory addresses are deterministic teaching data, not addresses read from a running process.")],-1)),r(n,{locale:"en"}),e[3]||(e[3]=d(`<p>Initialization waits for the required system-stub scans, suspends the thread once to capture the <code>INTEGER</code>, <code>CONTROL</code>, and <code>FLOATING_POINT</code> context groups, then resumes it once into the running <code>EB FE</code> spin loop. For readability, the simulator shows <code>RIP</code>, <code>RSP</code>, <code>RAX</code>, <code>RBX</code>, <code>RBP</code>, <code>RCX</code>, <code>RDX</code>, <code>R8</code>, and <code>R9</code>; its NThread side handles those nine fields only through <code>getContext()</code> and <code>setContext()</code>. The real snapshot also contains XMM state. Restoring context cannot undo lock semantics or memory side effects produced by a call.</p><p>Outside that initial <code>SuspendThread()</code> and <code>ResumeThread()</code> pair, the call path does not touch the thread&#39;s suspend count. Because <code>EB FE</code> changes neither registers nor memory, NThread can safely read and modify the context while the thread is running at spin.</p><p><code>savedContext</code> is copied twice during initialization. The first copy preserves the original <code>RIP</code> and selected jump-register value while the thread is initially suspended. After the <code>jumpStub → spinStub</code> landing, NThread clones the live context again while the thread runs at spin, then patches that second copy&#39;s <code>RIP</code> and jump-register field with the original values. The working snapshot therefore reflects the spin state while deinitialization can still release the thread at its captured instruction. The simulator&#39;s <code>CONTEXT BUS</code> and <code>0/2 → 2/2 COPIES</code> indicators visualize this sequence.</p><p>NThread leaves a full page below the captured stack pointer before selecting its call workspace:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>stackBegin = align16(capturedRsp - 4096)</span></span>
<span class="line"><span>callRsp    = stackBegin - 136</span></span>
<span class="line"><span></span></span>
<span class="line"><span>example: capturedRsp = 0x000000A418F8C8C0</span></span>
<span class="line"><span>         stackBegin  = 0x000000A418F8B8C0</span></span>
<span class="line"><span>         callRsp     = 0x000000A418F8B838</span></span></code></pre></div><p>The 4096-byte slack reduces the chance that stale dispatch pointers left in stack memory collide early with ordinary stack use after deinitialization. Stack memory itself is not restored.</p><h2 id="two-stage-return-chain" tabindex="-1">Two-stage return chain <a class="header-anchor" href="#two-stage-return-chain" aria-label="Permalink to &quot;Two-stage return chain&quot;">​</a></h2><p>NThread constructs its normal call return path by executing <code>push reg; ret</code> in two stages. Stage A uses <code>RSP = callRsp + 56</code> and <code>push spinStub; ret</code>, establishing the spin stub slot at <code>[callRsp + 48]</code>. Stage B uses <code>RSP = callRsp + 8</code> and <code>push addRsp28RetStub; ret</code>; its first return enters <code>add rsp, 0x28; ret</code> and its second return reaches the spin stub slot.</p><p><code>add rsp, 0x28</code> executes between the two <code>ret</code> instructions. These two return jumps exercise the normal zero-stack-argument return route before a user call is dispatched. Landing at the expected destination after both returns establishes and validates the cleanup, shadow-space skip, and known running spin state that later calls rely on for stability. Initialization fails if either stage does not return to spin as expected.</p><h2 id="one-call" tabindex="-1">One call <a class="header-anchor" href="#one-call" aria-label="Permalink to &quot;One call&quot;">​</a></h2><p>While the thread is running in the <code>EB FE</code> loop at <code>spinStub</code>, NThread reads its context with <code>getContext()</code>, prepares arguments and any required stack slots, then uses <code>setContext()</code> to point <code>RIP</code> at the target. The call path does not invoke <code>SuspendThread()</code> or <code>ResumeThread()</code>. After the target returns through the cleaner chain, the poller observes <code>RIP == spinStub</code> and reads the result from context. Between calls, the enabled thread remains running in the spin loop rather than roaming through native application code.</p><p>Calls with more than four parameters use an additional stack-cleanup stub. NThread attempts to write the basic zero-stack-argument return chain back after such a call. <code>call()</code> polls asynchronously; <code>callSync()</code> busy-spins the JavaScript thread without yielding and is suitable only for near-immediate calls. A timeout means the thread did not return to the known spin point, not merely that a function was slow.</p><h2 id="cleanup-and-failure" tabindex="-1">Cleanup and failure <a class="header-anchor" href="#cleanup-and-failure" aria-label="Permalink to &quot;Cleanup and failure&quot;">​</a></h2><p><code>deinit()</code> reapplies the saved context while the thread is running at spin, allowing execution to continue from the original <code>RIP</code> without another resume; it then frees temporary stack-argument stubs and closes the thread handle. Always deinitialize in <code>finally</code>. Do not blindly reuse an accessor after a timeout or thread death because the thread&#39;s live state may be unknown.</p><p>If an automatic demo call is in flight, the simulator&#39;s <strong>Disable</strong> control waits for that call to return to spin before showing <code>deinit()</code>. That ordering belongs to the UI; production lifecycle ownership must avoid racing <code>call()</code> against <code>deinit()</code>.</p>`,15))])}const w=o(l,[["render",h]]);export{y as __pageData,w as default};
